@app.route("/reset-mfa", methods=["POST"])
def reset_mfa():
    data = request.get_json(silent=True) or {}
    email = (data.get("email") or "").lower().strip()

    if email:
        user = get_user_by_email(email)
        if user:
            token = create_reset_token(email)
            reset_url = request.host_url.rstrip("/") + "/reset-mfa/confirm?token=" + token
            send_email(
                to_email=email,
                subject="Reset your MFA",
                body=(
                    "We received a request to reset MFA for your account.\n\n"
                    f"Use the following link to reset MFA:\n{reset_url}\n\n"
                    f"This link expires in {app.config['RESET_TOKEN_EXPIRY_SECONDS'] // 60} minutes."
                )
            )

    return jsonify({
        "message": "If the email is registered, a reset link has been sent."
    }), 200


@app.route("/reset-mfa/confirm", methods=["GET", "POST"])
def confirm_reset_mfa():
    token = request.args.get("token") or (request.get_json(silent=True) or {}).get("token")
    if not token:
        return jsonify({"error": "Token is required"}), 400

    try:
        email = verify_reset_token(token)
    except SignatureExpired:
        return jsonify({"error": "Reset link has expired"}), 400
    except BadSignature:
        return jsonify({"error": "Invalid reset link"}), 400

    user = get_user_by_email(email)
    if not user:
        return jsonify({"error": "User not found"}), 404

    user["mfa_enabled"] = False
    user["mfa_secret"] = None

    return jsonify({
        "message": "MFA has been reset. You can now log in using only your password."
    }), 200


